INSERT INTO public.photos VALUES (21075, 'San Miguel c.1877', 'Todo el "aire" alrededor del cuadro seleccionado por Laurent y Câ”œÂ¡a para editar la producida imagen final, amplâ”œÂ¡a el foco, y aâ”œâ–’ade una muy interesante panorâ”œÃ­mica de la antigua plaza de San Miguel, tanto por los elementos de la izquierda (engarce con la puerta del Duque de la Victoria), de la derecha (antiguas viviendas de los nâ”œâ•‘meros 14 y 15 de la plaza), como de la parte inferior, que indica que la imagen se capturâ”œâ”‚ en altura. Fuente visual: Jean Laurent y Câ”œÂ¡a, Archivo Ruiz Vernacci (Fototeca del Patrimonio Histâ”œâ”‚rico, www.mcu.es/)', 1877, 1877, 1877, 'Siglo XIX', 'CENTRO', 41.64958700, -0.87634200, '0101000020E6100000368FC360FE0AECBF1074B4AA25D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22091118443.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22091118443.webp', 'https://www.flickr.com/photos/zaragozaantigua/22091118443/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
