INSERT INTO public.photos VALUES (21127, 'Calle de San Miguel 1880', 'Entorno del Real convento de Religiosas Franciscanas de Santa Catalina trazado en el plano de Dionisio Casaâ”œâ–’al de 1880, segâ”œâ•‘n una copia firmada por el arquitecto municipal Ricardo Magdalena en 1895 con motivo de la nueva alineaciâ”œâ”‚n de la calle de San Miguel y el ensanche en la antigua Huerta de Santa Engracia, que supuso alguna expropiaciâ”œâ”‚n de la antigua huerta del franciscano convento de Santa Catalina, ademâ”œÃ­s de la remodelaciâ”œâ”‚n de la fachada principal de ingreso desde la calle de San Miguel, frente a la calle de Santa Catalina, y el levantamiento de un nuevo cerramiento perimetral, segâ”œâ•‘n diseâ”œâ–’o de Ricardo Magdalena. Fuente visual: Real Audiencia de Aragâ”œâ”‚n, AHPZ.', 1880, 1880, 1880, 'Siglo XIX', 'CENTRO', 41.65035800, -0.87902300, '0101000020E61000005FD1ADD7F420ECBF925852EE3ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40306768155.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40306768155.webp', 'https://www.flickr.com/photos/zaragozaantigua/40306768155/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21184, 'San Miguel 1890', 'Imagen centrada en la iglesia parroquial de San Miguel de los Navarros y las viviendas a ella adosadas, capturada a cierta altura desde la homâ”œâ”‚nima plaza, de la que emerge vegetaciâ”œâ”‚n arbâ”œâ”‚rea que modelaba su rotonda central. La torre perfila su remate anterior a la intervenciâ”œâ”‚n diseâ”œâ–’ada por Ricardo Magdalena. A la izquierda, detalle del engarce de la iglesia con el cerramiento de la antigua puerta del Duque de la Victoria, cuya sombra se proyecta sobre el exterior del â”œÃ­bside mudâ”œÂ®jar. Fuente visual: "Iglesia de San Miguel de los Navarros", fototipia de Joarizti y Mariezcurrena, en Ã”Ã‡Â£Zaragoza Artâ”œÂ¡stica, Monumental e Histâ”œâ”‚ricaÃ”Ã‡Ã˜, Anselmo y Pedro Gascâ”œâ”‚n de Gotor (1890-91).', 1890, 1890, 1890, 'Siglo XIX', 'CENTRO', 41.64951900, -0.87615100, '0101000020E61000003F726BD26D09ECBFB890477023D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34224412650.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34224412650.webp', 'https://www.flickr.com/photos/zaragozaantigua/34224412650/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
