INSERT INTO public.photos VALUES (21259, 'Convento de Santa Catalina 1907', 'Postal. "Colecciâ”œâ”‚n Patria y Fe nâ”œâ•‘m. 26, Zaragoza 1908 - Centenario de los Sitios", 1907. "Uno de los edificios que mâ”œÃ­s sufrieron durante el primer sitio. Los franceses lo atacaron violentamente porque a espaldas del convento, en el Jardâ”œÂ¡n Botâ”œÃ­nico, fueron colocadas dos baterâ”œÂ¡as con las que los zaragozanos les desbarataban todos sus planes." Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CENTRO', 41.65028900, -0.87892500, '0101000020E6100000AA6054522720ECBF6AF981AB3CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20583351800.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20583351800.webp', 'https://www.flickr.com/photos/zaragozaantigua/20583351800/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
